// ─── AUDIO HOOK ───────────────────────────────────────────────────────────────
function useAmbientAudio() {
  const [activeTrack, setActiveTrack] = useState(null);
  const [isPlaying, setIsPlaying]     = useState(false);
  const audioRefs = useRef({});

  const getAudio = (track) => {
    if (!audioRefs.current[track.id]) {
      const audio = new Audio(track.url);
      audio.loop = true; audio.volume = 0; audio.preload = "none";
      audio.addEventListener("error", () =>
        console.warn(`Audio failed: ${track.label} — place MP3s in /public/uploads/`));
      audioRefs.current[track.id] = audio;
    }
    return audioRefs.current[track.id];
  };

  const fadeIn  = (audio, vol=0.35, ms=3000) => {
    const steps=40, st=ms/steps, dv=vol/steps; let s=0;
    const t=setInterval(()=>{ s++; audio.volume=Math.min(vol,audio.volume+dv); if(s>=steps)clearInterval(t); },st);
  };
  const fadeOut = (audio, ms=2500, cb) => {
    const sv=audio.volume, steps=40, st=ms/steps, dv=sv/steps; let s=0;
    const t=setInterval(()=>{ s++; audio.volume=Math.max(0,audio.volume-dv);
      if(s>=steps){ clearInterval(t); audio.pause(); audio.volume=0; cb&&cb(); } },st);
  };

  const playTrack = useCallback((track) => {
    if (activeTrack?.id === track.id) {
      fadeOut(getAudio(track),2000); setActiveTrack(null); setIsPlaying(false); return;
    }
    if (activeTrack) fadeOut(getAudio(activeTrack),2000);
    const a=getAudio(track); a.currentTime=0; a.play().catch(()=>{});
    fadeIn(a,0.35,3000); setActiveTrack(track); setIsPlaying(true);
  }, [activeTrack]);


  const autoPlay = useCallback(() => {
    if (!activeTrack) {
      const track = AMBIENT_TRACKS[0];
      const a = getAudio(track); a.currentTime=0; a.play().catch(()=>{});
      fadeIn(a,0.35,3000); setActiveTrack(track); setIsPlaying(true);
    }
  }, [activeTrack]);
  useEffect(()=>()=>Object.values(audioRefs.current).forEach(a=>a.pause()),[]);
  return { activeTrack, isPlaying, playTrack, autoPlay };
}

// ─── BREATHING CIRCLE ─────────────────────────────────────────────────────────
function BreathingCircle() {
  const [phase,setPhase]=useState("inhale");
  const [expanded,setExpanded]=useState(false);
  const tRef=useRef();
  useEffect(()=>{
    const cycle=[{phase:"inhale",dur:4000,exp:true},{phase:"hold",dur:2000,exp:true},{phase:"exhale",dur:6000,exp:false}];
    let i=0; const run=()=>{ const s=cycle[i%3]; setPhase(s.phase); setExpanded(s.exp); tRef.current=setTimeout(run,s.dur); i++; };
    run(); return ()=>clearTimeout(tRef.current);
  },[]);
  const size=expanded?70:36;
  const dur=phase==="inhale"?"4s":phase==="hold"?"0.2s":"6s";
  return (
    <div style={{position:"absolute",top:12,right:12,display:"flex",flexDirection:"column",
      alignItems:"center",gap:8,
      pointerEvents:"none",zIndex:20}}>
      <div style={{width:size,height:size,borderRadius:"50%",
        background:"radial-gradient(circle, rgba(255,255,255,0.9), rgba(182,209,201,0.6))",
        transition:`width ${dur} ease-in-out, height ${dur} ease-in-out`,
        boxShadow:"0 0 40px rgba(123,174,158,0.6), 0 0 80px rgba(182,209,201,0.3)"}}/>
      <span style={{fontSize:15,color:"#2c4a52",fontFamily:"Georgia, serif",
        letterSpacing:3,fontStyle:"italic",opacity:0.85}}>
        {{"inhale":"Inhale","hold":"Hold","exhale":"Exhale"}[phase]}
      </span>
    </div>
  );
}

