// ─── ZOOMABLE CANVAS ──────────────────────────────────────────────────────────
function ZoomableCanvas({ children }) {
  const [zoom, setZoom]       = useState(1);
  const [offset, setOffset]   = useState({ x: 0, y: 0 });
  const [dragging, setDragging] = useState(false);
  const lastTouch  = useRef(null);
  const lastPinch  = useRef(null);
  const lastMouse  = useRef(null);
  const containerRef = useRef(null);
  const tapTimer   = useRef(null);
  const lastTap    = useRef(0);

  const clampOffset = (ox, oy, z) => {
    if (!containerRef.current) return { x: ox, y: oy };
    const cw = containerRef.current.offsetWidth;
    const ch = containerRef.current.offsetHeight;
    const maxX = (cw * (z - 1)) / 2;
    const maxY = (ch * (z - 1)) / 2;
    return { x: Math.min(maxX, Math.max(-maxX, ox)), y: Math.min(maxY, Math.max(-maxY, oy)) };
  };

  // Double-tap to toggle zoom
  const handleTouchStart = (e) => {
    const now = Date.now();
    if (e.touches.length === 1) {
      if (now - lastTap.current < 300) {
        // Double tap
        clearTimeout(tapTimer.current);
        if (zoom > 1) {
          setZoom(1); setOffset({ x: 0, y: 0 });
        } else {
          const touch = e.touches[0];
          const rect = containerRef.current.getBoundingClientRect();
          const cx = touch.clientX - rect.left - rect.width / 2;
          const cy = touch.clientY - rect.top - rect.height / 2;
          const newZoom = 2.5;
          const clamped = clampOffset(-cx * (newZoom - 1), -cy * (newZoom - 1), newZoom);
          setZoom(newZoom); setOffset(clamped);
        }
        lastTap.current = 0;
        return;
      }
      lastTap.current = now;
      lastTouch.current = { x: e.touches[0].clientX, y: e.touches[0].clientY };
    } else if (e.touches.length === 2) {
      const dx = e.touches[0].clientX - e.touches[1].clientX;
      const dy = e.touches[0].clientY - e.touches[1].clientY;
      lastPinch.current = Math.sqrt(dx * dx + dy * dy);
    }
  };

  const handleTouchMove = (e) => {
    if (e.touches.length === 2 && lastPinch.current) {
      e.preventDefault();
      const dx = e.touches[0].clientX - e.touches[1].clientX;
      const dy = e.touches[0].clientY - e.touches[1].clientY;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const ratio = dist / lastPinch.current;
      lastPinch.current = dist;
      setZoom(z => {
        const nz = Math.min(4, Math.max(1, z * ratio));
        setOffset(o => clampOffset(o.x, o.y, nz));
        return nz;
      });
    } else if (e.touches.length === 1 && zoom > 1 && lastTouch.current) {
      e.preventDefault();
      const dx = e.touches[0].clientX - lastTouch.current.x;
      const dy = e.touches[0].clientY - lastTouch.current.y;
      lastTouch.current = { x: e.touches[0].clientX, y: e.touches[0].clientY };
      setOffset(o => clampOffset(o.x + dx, o.y + dy, zoom));
    }
  };

  const handleTouchEnd = () => { lastPinch.current = null; };

  // Double-click for desktop
  const handleDoubleClick = (e) => {
    if (zoom > 1) { setZoom(1); setOffset({ x: 0, y: 0 }); return; }
    const rect = containerRef.current.getBoundingClientRect();
    const cx = e.clientX - rect.left - rect.width / 2;
    const cy = e.clientY - rect.top - rect.height / 2;
    const newZoom = 2.5;
    const clamped = clampOffset(-cx * (newZoom - 1), -cy * (newZoom - 1), newZoom);
    setZoom(newZoom); setOffset(clamped);
  };

  // Mouse drag when zoomed
  const handleMouseDown = (e) => { if (zoom > 1) { setDragging(true); lastMouse.current = { x: e.clientX, y: e.clientY }; } };
  const handleMouseMove = (e) => {
    if (!dragging || !lastMouse.current) return;
    const dx = e.clientX - lastMouse.current.x;
    const dy = e.clientY - lastMouse.current.y;
    lastMouse.current = { x: e.clientX, y: e.clientY };
    setOffset(o => clampOffset(o.x + dx, o.y + dy, zoom));
  };
  const handleMouseUp = () => setDragging(false);

  return (
    <div ref={containerRef} style={{ position: "relative", width: "100%", overflow: "hidden",
      cursor: zoom > 1 ? (dragging ? "grabbing" : "grab") : "default",
      touchAction: zoom > 1 ? "none" : "auto" }}
      onTouchStart={handleTouchStart} onTouchMove={handleTouchMove} onTouchEnd={handleTouchEnd}
      onDoubleClick={handleDoubleClick}
      onMouseDown={handleMouseDown} onMouseMove={handleMouseMove} onMouseUp={handleMouseUp} onMouseLeave={handleMouseUp}>
      <div style={{ transform: `translate(${offset.x}px, ${offset.y}px) scale(${zoom})`,
        transformOrigin: "center center", transition: dragging ? "none" : "transform 0.1s ease",
        willChange: "transform" }}>
        {children}
      </div>
      {zoom > 1 && (
        <button onClick={() => { setZoom(1); setOffset({ x: 0, y: 0 }); }}
          style={{ position: "absolute", top: 8, right: 8, background: "rgba(255,255,255,0.85)",
            border: "none", borderRadius: 10, padding: "5px 10px", fontSize: 11,
            color: "#3d5a66", cursor: "pointer", fontFamily: "Georgia, serif",
            boxShadow: "0 2px 8px rgba(0,0,0,0.1)", zIndex: 20 }}>
          Reset Zoom
        </button>
      )}
      <div style={{ position: "absolute", bottom: 8, left: "50%", transform: "translateX(-50%)",
        background: "rgba(255,255,255,0.7)", borderRadius: 8, padding: "3px 8px",
        fontSize: 9, color: "#6a8a96", fontFamily: "Georgia, serif", pointerEvents: "none",
        opacity: zoom === 1 ? 0.7 : 0 }}>
        Double-tap to zoom
      </div>
    </div>
  );
}

// ─── COLORING SVG ─────────────────────────────────────────────────────────────
function ColoringSVG({ artId, coloredZones, onZoneClick, mode, activeColor, activeNumber }) {
  const isSatori = artId === "satori";
  const artZones = isSatori ? SATORI_ZONES : COLOR_ZONES;
  const [hoveredId, setHoveredId] = useState(null);
  const [glowId, setGlowId]       = useState(null);

  const handleClick = (zone) => {
    if (coloredZones[zone.id]) return;
    if (mode === "number" && activeNumber !== zone.paletteId) return;
    setGlowId(zone.id);
    setTimeout(() => setGlowId(null), 700);
    onZoneClick(zone.id);
  };

  if (isSatori) {
    return (
      <svg viewBox="0 0 600 450"
        style={{ width:"100%", display:"block",
          filter:"drop-shadow(0 6px 20px rgba(60,90,100,0.15))" }}>
        <defs>
          <filter id="satori-glow">
            <feGaussianBlur stdDeviation="3" result="b"/>
            <feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge>
          </filter>
        </defs>
        <rect width="600" height="450" fill="#FAF8F4"/>
        {/* Colored polygon fills */}
        {SATORI_ZONES.map(zone => {
          const pal = SATORI_PALETTE.find(p => p.id === zone.paletteId);
          if (!pal || !zone.points) return null;
          const filled  = coloredZones[zone.id];
          const hovered = hoveredId === zone.id && !filled;
          const glowing = glowId === zone.id;
          const fillColor = filled || (hovered ? (activeColor || pal.color + "99") : null);
          if (!fillColor) return null;
          const pts = zone.points.map(p => p.join(',')).join(' ');
          return (
            <polygon key={zone.id} points={pts} fill={fillColor}
              opacity={filled ? 0.85 : 0.5}
              style={{ filter: glowing ? "url(#satori-glow)" : "none", transition:"opacity 0.3s" }}/>
          );
        })}
        {/* Artwork paths on top */}
        <g transform="translate(0,450) scale(0.05,-0.05)" stroke="none">
          {SATORI_COLORED_PATHS.map((d,i) => (
            <path key={i} d={d} fill={SATORI_PALETTE.find(p=>p.id===SATORI_ZONES[i]?.paletteId)?.color || "#ccc"} opacity="0.35"/>
          ))}
          {SATORI_BLACK_PATHS.map((d,i) => <path key={"b"+i} d={d} fill="#444"/>)}
        </g>
        {/* Hit areas */}
        {SATORI_ZONES.map(zone => {
          if (!zone.points) return null;
          const pts = zone.points.map(p => p.join(',')).join(' ');
          return (
            <polygon key={"hit-"+zone.id} points={pts} fill="transparent" stroke="none"
              style={{ cursor: coloredZones[zone.id] ? "default" : "pointer" }}
              onMouseEnter={() => setHoveredId(zone.id)}
              onMouseLeave={() => setHoveredId(null)}
              onClick={() => handleClick(zone)}/>
          );
        })}
        {/* Number labels */}
        {mode === "number" && SATORI_ZONES.map(zone => {
          if (coloredZones[zone.id] || !zone.points) return null;
          const xs = zone.points.map(p => p[0]), ys = zone.points.map(p => p[1]);
          const cx = xs.reduce((a,b)=>a+b,0)/xs.length;
          const cy = ys.reduce((a,b)=>a+b,0)/ys.length;
          const isActive = activeNumber === zone.paletteId;
          const colorIndex = [...new Set(SATORI_ZONES.map(z=>z.paletteId))].indexOf(zone.paletteId) + 1;
          return (
            <g key={"num-"+zone.id} style={{ pointerEvents:"none" }}>
              <circle cx={cx} cy={cy} r={8}
                fill={isActive ? "rgba(123,174,158,0.9)" : "rgba(255,255,255,0.88)"}
                stroke={isActive ? "#3d6b5a" : "rgba(100,130,140,0.35)"} strokeWidth={1}/>
              <text x={cx} y={cy+3} textAnchor="middle" fontSize="7"
                fontWeight={isActive?"700":"500"}
                fill={isActive?"#fff":"#4a6a78"}>{colorIndex}</text>
            </g>
          );
        })}
      </svg>
    );
  }

  return (
    <svg viewBox="0 0 450 600"
      style={{ width: "100%", display: "block",
        filter: "drop-shadow(0 6px 20px rgba(60,90,100,0.15))" }}>
      <defs>
        {COLOR_ZONES.map(z => (
          <clipPath key={`cp-${z.id}`} id={`cp-${z.id}`}>
            <path d={z.clipPath}/>
          </clipPath>
        ))}
        <filter id="glow">
          <feGaussianBlur stdDeviation="3" result="b"/>
          <feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge>
        </filter>
      </defs>

      {/* Paper background */}
      <rect width="450" height="600" fill="#FAF8F4"/>

      {/* Colored fills — behind line art */}
      {COLOR_ZONES.map(zone => {
        const filled  = coloredZones[zone.id];
        const hovered = hoveredId === zone.id && !filled;
        const glowing = glowId === zone.id;
        const fillColor = filled || (hovered ? (activeColor || "rgba(182,209,201,0.4)") : null);
        if (!fillColor) return null;
        return (
          <g key={zone.id} clipPath={`url(#cp-${zone.id})`}>
            <rect width="450" height="600" fill={fillColor}
              opacity={filled ? 0.85 : 0.45}
              style={{ filter: glowing ? "url(#glow)" : "none", transition: "opacity 0.3s" }}/>
          </g>
        );
      })}

      {/* Hit areas */}
      {COLOR_ZONES.map(zone => (
        <path key={`hit-${zone.id}`} d={zone.clipPath} fill="transparent" stroke="none"
          style={{ cursor: coloredZones[zone.id] ? "default" : "pointer" }}
          onMouseEnter={() => setHoveredId(zone.id)}
          onMouseLeave={() => setHoveredId(null)}
          onClick={() => handleClick(zone)}/>
      ))}

      {/* Line art on top */}
      <g transform="translate(0,600) scale(0.1,-0.1)" fill="#2c3e45" stroke="none">
        {LOGO_PATHS.map((d, i) => <path key={i} d={d}/>)}
      </g>

      {/* Number labels — shared number per color group */}
      {mode === "number" && !isSatori && COLOR_ZONES.map((zone) => {
        if (coloredZones[zone.id]) return null;
        const nums = zone.clipPath.match(/[\d.]+/g).map(Number);
        const xs = nums.filter((_,i) => i%2===0);
        const ys = nums.filter((_,i) => i%2===1);
        const cx = xs.reduce((a,b)=>a+b,0)/xs.length;
        const cy = ys.reduce((a,b)=>a+b,0)/ys.length;
        const isActive = activeNumber === zone.paletteId;
        const colorIndex = [...new Set(COLOR_ZONES.map(z=>z.paletteId))].indexOf(zone.paletteId) + 1;
        return (
          <g key={`num-${zone.id}`} style={{ pointerEvents: "none" }}>
            <circle cx={cx} cy={cy} r={10}
              fill={isActive ? "rgba(123,174,158,0.9)" : "rgba(255,255,255,0.88)"}
              stroke={isActive ? "#3d6b5a" : "rgba(100,130,140,0.35)"} strokeWidth={1}/>
            <text x={cx} y={cy+4} textAnchor="middle"
              fontSize="9" fontWeight={isActive?"700":"500"}
              fill={isActive?"#fff":"#4a6572"} fontFamily="Georgia, serif">
              {colorIndex}
            </text>
          </g>
        );
      })}
    </svg>
  );
}

// ─── SCROLLABLE PALETTE BAR ───────────────────────────────────────────────────
function PaletteBar({ mode, selectedColor, setSelectedColor, activeNumber, setActiveNumber, coloredZones, artZones, artPalette }) {
  const scrollRef = useRef(null);

  if (mode === "number") {
    // Build unique color groups — one button per paletteId
    const uniquePalettes = [...new Set(artZones.map(z => z.paletteId))];
    return (
      <div style={{ padding: "8px 0 14px" }}>
        <p style={{ textAlign:"center", fontFamily:"Georgia, serif", fontSize:10,
          color:"#6a8a96", fontStyle:"italic", margin:"0 0 8px" }}>
          Select a color · tap matching zones to paint
        </p>
        <div ref={scrollRef} style={{ display:"flex", gap:10, overflowX:"auto", padding:"6px 16px 4px",
          scrollbarWidth:"none", msOverflowStyle:"none", justifyContent:"center" }}
          onWheel={e => { e.preventDefault(); scrollRef.current.scrollLeft += e.deltaY; }}>
          {uniquePalettes.map((pid, idx) => {
            const pal = artPalette.find(p => p.id === pid);
            const zonesForColor = artZones.filter(z => z.paletteId === pid);
            const allFilled = zonesForColor.every(z => !!coloredZones[z.id]);
            const isActive = activeNumber === pid;
            const colorNum = idx + 1;
            return (
              <button key={pid} onClick={() => setActiveNumber(isActive ? null : pid)}
                title={pal?.name}
                style={{ flexShrink:0, width:64, height:64, borderRadius:16,
                  background: pal?.color || "#ccc",
                  border: isActive ? "3px solid #2c4a52" : "2.5px solid rgba(255,255,255,0.85)",
                  cursor:"pointer", display:"flex", flexDirection:"column",
                  alignItems:"center", justifyContent:"center", gap:2,
                  boxShadow: isActive ? "0 0 0 3px rgba(123,174,158,0.5),0 3px 12px rgba(0,0,0,0.15)"
                                      : "0 2px 8px rgba(0,0,0,0.12)",
                  opacity: allFilled ? 0.38 : 1, transition:"all 0.18s ease",
                  fontFamily:"Georgia, serif" }}>
                <span style={{ fontSize:20, fontWeight:700, color:"rgba(255,255,255,0.95)",
                  textShadow:"0 1px 3px rgba(0,0,0,0.4)", lineHeight:1 }}>
                  {allFilled ? "✓" : colorNum}
                </span>
                <span style={{ fontSize:8, color:"rgba(255,255,255,0.85)",
                  textShadow:"0 1px 2px rgba(0,0,0,0.3)", letterSpacing:0.5,
                  maxWidth:56, textAlign:"center", lineHeight:1.2, overflow:"hidden",
                  textOverflow:"ellipsis", whiteSpace:"nowrap" }}>
                  {pal?.name}
                </span>
              </button>
            );
          })}
        </div>
      </div>
    );
  }

  // Free color mode — scrollable color swatches
  return (
    <div style={{ padding: "8px 0 14px" }}>
      <p style={{ textAlign:"center", fontFamily:"Georgia, serif", fontSize:10,
        color:"#6a8a96", fontStyle:"italic", margin:"0 0 8px" }}>
        Choose a color · tap any zone to paint
      </p>
      <div ref={scrollRef} style={{ display:"flex", gap:10, overflowX:"auto", padding:"6px 16px 4px",
        scrollbarWidth:"none", msOverflowStyle:"none", alignItems:"center" }}
        onWheel={e => { e.preventDefault(); scrollRef.current.scrollLeft += e.deltaY; }}>
        {artPalette.map(p => (
          <button key={p.id} onClick={() => setSelectedColor(p.color)} title={p.name}
            style={{ flexShrink:0, width: selectedColor===p.color ? 44 : 36,
              height: selectedColor===p.color ? 44 : 36, borderRadius:"50%",
              background:p.color,
              border: selectedColor===p.color ? "3px solid #2c4a52" : "2.5px solid rgba(255,255,255,0.85)",
              cursor:"pointer",
              boxShadow: selectedColor===p.color
                ? "0 0 0 2.5px rgba(123,174,158,0.5),0 2px 8px rgba(0,0,0,0.14)"
                : "0 1px 5px rgba(0,0,0,0.1)",
              transition:"all 0.18s ease" }}/>
        ))}
      </div>
    </div>
  );
}

// ─── IMAGE VIEW ───────────────────────────────────────────────────────────────
function ImageView({ artId, onBack, audio, onProgress }) {
  const isSatori = artId === "satori";
  const artPalette = isSatori ? SATORI_PALETTE : PALETTE;
  const artZones   = isSatori ? SATORI_ZONES   : COLOR_ZONES;
  const [mode, setMode]                 = useState(null);
  const [coloredZones, setColoredZones] = useState({});
  const artPaletteInit = artId === "satori" ? SATORI_PALETTE : PALETTE;
  const [selectedColor, setSelectedColor] = useState(artPaletteInit[0].color);
  const [activeNumber, setActiveNumber] = useState(null);
  const [zenMode, setZenMode]           = useState(false);
  const [showReset, setShowReset]       = useState(false);
  const [showComplete, setShowComplete] = useState(false);
  const [showAmbient, setShowAmbient]   = useState(false);
  const [affirmation, setAffirmation]   = useState("");

  const totalZones  = artZones.length;
  const filledCount = Object.keys(coloredZones).length;
  const completion  = Math.round((filledCount / totalZones) * 100);

  const handleZoneClick = useCallback((zoneId) => {
    const zone = artZones.find(z => z.id === zoneId);
    if (!zone || coloredZones[zoneId]) return;
    const fillColor = mode === "number"
      ? artPalette.find(p => p.id === zone.paletteId)?.color
      : selectedColor;
    if (!fillColor) return;
    setColoredZones(prev => {
      const next = { ...prev, [zoneId]: fillColor };
      if (Object.keys(next).length === totalZones) {
        const aff = AFFIRMATIONS[Math.floor(Math.random() * AFFIRMATIONS.length)];
        setTimeout(() => { setAffirmation(aff); setShowComplete(true); }, 700);
      }
      return next;
    });
  }, [coloredZones, mode, activeNumber, selectedColor, totalZones]);

  const activeColor = mode === "number"
    ? (activeNumber ? artPalette.find(p => p.id === activeNumber)?.color : null)
    : selectedColor;

  // Mode selection screen
  if (!mode) {
    return (
      <div style={{ minHeight:"100vh", background:"#B6D1C9", display:"flex",
        flexDirection:"column", alignItems:"center", justifyContent:"center", padding:24 }}>
        <button onClick={onBack} style={{ position:"absolute", top:20, left:16,
          background:"rgba(255,255,255,0.55)", border:"none", borderRadius:12,
          padding:"8px 14px", fontSize:14, color:"#3d5a66", cursor:"pointer",
          fontFamily:"Georgia, serif" }}>← Gallery</button>
        <div style={{ marginBottom:24, borderRadius:16, overflow:"hidden",
          boxShadow:"0 6px 28px rgba(40,60,70,0.2)", width:150, background:"#FAF8F4" }}>
          {isSatori ? (
            <svg viewBox="0 0 600 450" style={{ width:"100%", display:"block", background:"#FAF8F4" }}>
              {SATORI_COLORED_PATHS.map((d,i)=>(
                <g key={i} transform="translate(0,450) scale(0.05,-0.05)">
                  <path d={d} fill={SATORI_PALETTE[SATORI_ZONES[i].paletteId-1].color}/>
                </g>
              ))}
              <g transform="translate(0,450) scale(0.05,-0.05)" fill="#555" stroke="none">
                {SATORI_BLACK_PATHS.map((d,i)=><path key={i} d={d}/>)}
              </g>
            </svg>
          ) : (
            <svg viewBox="0 0 450 600" style={{ width:"100%", display:"block" }}>
              <rect width="450" height="600" fill="#FAF8F4"/>
              <defs>{COLOR_ZONES.map(z=>(<clipPath key={z.id} id={"ms_"+z.id}><path d={z.clipPath}/></clipPath>))}</defs>
              {COLOR_ZONES.map(z=>{const p=PALETTE.find(p=>p.id===z.paletteId);if(!p)return null;return(<g key={z.id} clipPath={"url(#ms_"+z.id+")"}><rect width="450" height="600" fill={p.color} opacity="0.9"/></g>);})}
              <g transform="translate(0,600) scale(0.1,-0.1)" fill="#2c3e45" stroke="none">{LOGO_PATHS.map((d,i)=><path key={i} d={d}/>)}</g>
            </svg>
          )}
        </div>
        <h2 style={{ fontFamily:"Georgia, serif", color:"#2c4a52", fontSize:18, marginBottom:4,
          letterSpacing:3, textAlign:"center", fontWeight:400 }}>{isSatori ? "SATORI" : "TIGER CLAW"}</h2>
        <p style={{ fontFamily:"Georgia, serif", color:"#5a7a8a", fontSize:13, marginBottom:32,
          fontStyle:"italic" }}>Choose your style</p>
        {[
          { key:"number", label:"Color by Number", sub:"Each zone has a guided suggested color" },
          { key:"free",   label:"Free Color",       sub:"Paint any zone with any color you like" },
        ].map(opt => (
          <button key={opt.key} onClick={() => { setMode(opt.key); audio.autoPlay(); }} style={{
            width:"100%", maxWidth:300, background:"rgba(255,255,255,0.75)",
            border:"none", borderRadius:18, padding:"18px 22px", marginBottom:12,
            textAlign:"left", cursor:"pointer",
            boxShadow:"0 3px 18px rgba(60,90,100,0.1)", transition:"transform 0.18s ease"}}
            onMouseEnter={e=>e.currentTarget.style.transform="scale(1.02)"}
            onMouseLeave={e=>e.currentTarget.style.transform="scale(1)"}>
            <div style={{ fontFamily:"Georgia, serif", fontSize:15, color:"#2c4a52", fontWeight:600 }}>{opt.label}</div>
            <div style={{ fontFamily:"Georgia, serif", fontSize:11, color:"#7a9aaa", marginTop:3, fontStyle:"italic" }}>{opt.sub}</div>
          </button>
        ))}
      </div>
    );
  }

  return (
    <div style={{ minHeight:"100vh", background:"#B6D1C9", display:"flex", flexDirection:"column" }}>
      {/* Header */}
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between",
        padding:"14px 14px 10px", background:"rgba(255,255,255,0.42)",
        backdropFilter:"blur(10px)", borderBottom:"1px solid rgba(255,255,255,0.35)" }}>
        <button onClick={onBack} style={{ background:"none", border:"none", cursor:"pointer",
          color:"#3d5a66", fontSize:14, fontFamily:"Georgia, serif" }}>← Back</button>
        <div style={{ textAlign:"center" }}>
          <div style={{ fontFamily:"Georgia, serif", fontSize:11, letterSpacing:3, color:"#2c4a52" }}>{isSatori ? "SATORI" : "TIGER CLAW"}</div>
          <div style={{ fontSize:10, color:"#6a8a96", marginTop:1 }}>{completion}% complete</div>
        </div>
        <div style={{ display:"flex", gap:6 }}>
          <button onClick={() => setMode(m => m==="number"?"free":"number")}
            style={{ background:"rgba(255,255,255,0.65)", border:"none", borderRadius:9,
              padding:"5px 9px", fontSize:11, cursor:"pointer", color:"#3d5a66" }}>
            {mode==="number" ? (
              /* Paintbrush icon for switching to Free Color */
              <svg width="18" height="18" viewBox="0 0 18 18" fill="none" stroke="#3d5a66" strokeWidth="1.3" strokeLinecap="round" strokeLinejoin="round">
                <line x1="13" y1="2" x2="6" y2="10"/>
                <line x1="14.5" y1="3.5" x2="7.5" y2="11.5"/>
                <path d="M6 10 Q4 13 3 15 Q5.5 14.5 7.5 11.5"/>
                <ellipse cx="10" cy="6.5" rx="1.2" ry="2.8" transform="rotate(-45 10 6.5)"/>
              </svg>
            ) : (
              /* Target/number icon for switching to Color by Number */
              <svg width="18" height="18" viewBox="0 0 18 18" fill="none" stroke="#3d5a66" strokeWidth="1.3" strokeLinecap="round">
                <circle cx="9" cy="9" r="6.5"/>
                <circle cx="9" cy="9" r="3.5"/>
                <circle cx="9" cy="9" r="1"/>
                <line x1="9" y1="1" x2="9" y2="3.5"/>
                <line x1="9" y1="14.5" x2="9" y2="17"/>
                <line x1="1" y1="9" x2="3.5" y2="9"/>
                <line x1="14.5" y1="9" x2="17" y2="9"/>
              </svg>
            )}
          </button>
          <button onClick={() => setZenMode(z => !z)}
            style={{ background:zenMode?"rgba(123,174,158,0.35)":"rgba(255,255,255,0.65)",
              border:"none", borderRadius:9, padding:"5px 9px", fontSize:11, cursor:"pointer" }}><span style={{display:"flex",flexDirection:"column",alignItems:"center",lineHeight:1.1}}>
                <span style={{fontSize:9,fontWeight:700,letterSpacing:1}}>ZEN</span>
                <span style={{fontSize:9,fontWeight:700,letterSpacing:1}}>MODE</span>
              </span></button>
          <button onClick={() => audio.isPlaying ? audio.playTrack(audio.activeTrack) : audio.autoPlay()}
            style={{ background:audio.isPlaying?"rgba(123,174,158,0.35)":"rgba(255,255,255,0.65)",
              border:"none", borderRadius:9, padding:"5px 9px", fontSize:11, cursor:"pointer" }}>
            {audio.isPlaying
              ? <span>🎵</span>
              : <span style={{position:"relative",display:"inline-block"}}>🎵<span style={{position:"absolute",left:-1,top:-2,fontSize:16,color:"#c0392b",fontWeight:900,lineHeight:1}}>&#47;</span></span>
            }
          </button>
        </div>
      </div>

      {/* Progress bar */}
      <div style={{ height:3, background:"rgba(255,255,255,0.25)" }}>
        <div style={{ height:"100%", width:`${completion}%`,
          background:"linear-gradient(to right,#C8453A,#7BAE9E)", transition:"width 0.5s ease" }}/>
      </div>

      {/* Zoomable Canvas */}
      <div style={{ flex:1, padding:"10px 12px 6px", position:"relative" }}>
        {zenMode && <BreathingCircle/>}
        <ZoomableCanvas>
          <div style={{ background:"#FAF8F4", borderRadius:12, overflow:"hidden",
            boxShadow:"0 4px 24px rgba(40,60,70,0.13)" }}>
            <ColoringSVG
              artId={artId}
              coloredZones={coloredZones}
              onZoneClick={handleZoneClick}
              mode={mode}
              activeColor={activeColor}
              activeNumber={activeNumber}/>
          </div>
        </ZoomableCanvas>
      </div>

      {/* Scrollable palette bar */}
      <div style={{ background:"rgba(255,255,255,0.5)", backdropFilter:"blur(8px)",
        borderTop:"1px solid rgba(255,255,255,0.4)" }}>
        <PaletteBar
          mode={mode}
          selectedColor={selectedColor}
          setSelectedColor={setSelectedColor}
          activeNumber={activeNumber}
          setActiveNumber={setActiveNumber}
          coloredZones={coloredZones}
          artZones={artZones}
          artPalette={artPalette}/>
      </div>

      {/* Start Over */}
      {!showReset ? (
        <button onClick={() => setShowReset(true)} style={{
          position:"fixed", bottom:90, right:14,
          background:"rgba(180,190,195,0.55)", border:"none", borderRadius:11,
          padding:"7px 13px", fontSize:10, color:"#3d5a66", cursor:"pointer",
          fontFamily:"Georgia, serif", backdropFilter:"blur(4px)" }}>Start Over</button>
      ) : (
        <div style={{ position:"fixed", bottom:80, right:12,
          background:"rgba(255,255,255,0.94)", borderRadius:16,
          padding:"14px 16px", boxShadow:"0 4px 22px rgba(60,90,100,0.14)", maxWidth:210 }}>
          <p style={{ fontFamily:"Georgia, serif", fontSize:12, color:"#3d5a66",
            margin:"0 0 10px", lineHeight:1.5 }}>Reset this image?</p>
          <div style={{ display:"flex", gap:8 }}>
            <button onClick={() => { setColoredZones({}); setShowReset(false); }}
              style={{ flex:1, background:"#D4A5A5", border:"none", borderRadius:9,
                padding:"7px", fontSize:11, color:"#fff", cursor:"pointer", fontFamily:"Georgia, serif" }}>Yes</button>
            <button onClick={() => setShowReset(false)}
              style={{ flex:1, background:"#e8eef0", border:"none", borderRadius:9,
                padding:"7px", fontSize:11, color:"#3d5a66", cursor:"pointer", fontFamily:"Georgia, serif" }}>Cancel</button>
          </div>
        </div>
      )}

      {showAmbient   && <AmbientPanel onClose={() => setShowAmbient(false)} audio={audio}/>}
      {showComplete  && <CompletionModal affirmation={affirmation} onClose={() => setShowComplete(false)}/>}
      <style>{`@keyframes fadeIn{from{opacity:0;transform:scale(0.97)}to{opacity:1;transform:scale(1)}}`}</style>
    </div>
  );
}

// ─── GALLERY ──────────────────────────────────────────────────────────────────
function GalleryThumb({ artId, onSelect, progress }) {
  const pct = Math.round(progress * 100);
  const done = pct === 100;
  const isSatori = artId === "satori";
  const label = isSatori ? "Satori" : "Tiger Claw";
  return (
    <div onClick={onSelect} style={{ background:"rgba(255,255,255,0.65)", borderRadius:18,
      overflow:"hidden", cursor:"pointer", boxShadow:"0 3px 18px rgba(60,90,100,0.11)",
      transition:"transform 0.2s ease,box-shadow 0.2s ease" }}
      onMouseEnter={e=>{e.currentTarget.style.transform="scale(1.03)";e.currentTarget.style.boxShadow="0 6px 26px rgba(60,90,100,0.18)"}}
      onMouseLeave={e=>{e.currentTarget.style.transform="scale(1)";e.currentTarget.style.boxShadow="0 3px 18px rgba(60,90,100,0.11)"}}>
      <div style={{ background:"rgba(245,248,250,0.7)", padding:"10px 10px 6px", position:"relative" }}>
        {isSatori ? (
          <svg viewBox="0 0 600 450" style={{ width:"100%", height:130, display:"block",
            background:"#FAF8F4", borderRadius:8 }}>
            {SATORI_COLORED_PATHS.map((d,i)=>(
              <g key={i} transform="translate(0,450) scale(0.05,-0.05)">
                <path d={d} fill={SATORI_PALETTE[SATORI_ZONES[i].paletteId-1].color}/>
              </g>
            ))}
            <g transform="translate(0,450) scale(0.05,-0.05)" fill="#444" stroke="none">
              {SATORI_BLACK_PATHS.map((d,i)=><path key={i} d={d}/>)}
            </g>
          </svg>
        ) : (
          <svg viewBox="0 0 450 600" style={{ width:"100%", height:130, display:"block",
            background:"#FAF8F4", borderRadius:8 }}>
            <defs>{COLOR_ZONES.map(z=>(<clipPath key={z.id} id={"th_"+z.id}><path d={z.clipPath}/></clipPath>))}</defs>
            {COLOR_ZONES.map(z=>{const p=PALETTE.find(p=>p.id===z.paletteId);if(!p)return null;return(<g key={z.id} clipPath={"url(#th_"+z.id+")"}><rect width="450" height="600" fill={p.color} opacity="0.9"/></g>);})}
            <g transform="translate(0,600) scale(0.1,-0.1)" fill="#2c3e45" stroke="none">{LOGO_PATHS.map((d,i)=><path key={i} d={d}/>)}</g>
          </svg>
        )}
        {done && <div style={{ position:"absolute", top:8, right:8, width:24, height:24,
          borderRadius:"50%", background:"#7BAE9E", display:"flex", alignItems:"center",
          justifyContent:"center", fontSize:12, color:"#fff" }}>✓</div>}
        {pct>0 && !done && (
          <div style={{ position:"absolute", top:8, right:8, width:28, height:28 }}>
            <svg viewBox="0 0 28 28">
              <circle cx="14" cy="14" r="11" fill="none" stroke="rgba(255,255,255,0.6)" strokeWidth="2.5"/>
              <circle cx="14" cy="14" r="11" fill="none" stroke="#7BAE9E" strokeWidth="2.5"
                strokeDasharray={`${2*Math.PI*11}`} strokeDashoffset={`${2*Math.PI*11*(1-pct/100)}`}
                transform="rotate(-90 14 14)"/>
            </svg>
          </div>
        )}
      </div>
      <div style={{ padding:"8px 12px 12px", textAlign:"center" }}>
        <span style={{ fontFamily:"Georgia, serif", fontSize:10, letterSpacing:2.5, color:"#3d5a66", textTransform:"uppercase" }}>{label}</span>
        {pct>0 && !done && <div style={{ marginTop:3 }}><span style={{ fontFamily:"Georgia, serif", fontSize:9, color:"#7BAE9E", fontStyle:"italic" }}>In Progress</span></div>}
      </div>
    </div>
  );
}

function HomeScreen({ onSelectImage, progress }) {
  return (
    <div style={{ minHeight:"100vh", background:"#B6D1C9" }}>
      <div style={{ padding:"42px 24px 22px", textAlign:"center",
        background:"rgba(255,255,255,0.18)", backdropFilter:"blur(8px)",
        borderBottom:"1px solid rgba(255,255,255,0.3)" }}>
        <h1 style={{ fontFamily:"Georgia, serif", fontSize:30, letterSpacing:6,
          color:"#2c4a52", margin:0, fontWeight:400 }}>CALM CANVAS</h1>
        <p style={{ fontFamily:"Georgia, serif", fontSize:13, color:"#4a6e7a",
          marginTop:8, fontStyle:"italic", letterSpacing:1.5 }}>color · breathe · be still</p>
      </div>
      <div style={{ padding:"24px 16px", display:"grid",
        gridTemplateColumns:"repeat(auto-fill,minmax(150px,1fr))", gap:16,
        maxWidth:500, margin:"0 auto" }}>
        <GalleryThumb artId="tiger" onSelect={()=>onSelectImage("tiger")} progress={progress.tiger||0}/>
        <GalleryThumb artId="satori" onSelect={()=>onSelectImage("satori")} progress={progress.satori||0}/>
        {[...Array(4)].map((_,i)=>(
          <div key={i} style={{ background:"rgba(255,255,255,0.28)", borderRadius:18, height:175,
            display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center",
            gap:8, border:"1.5px dashed rgba(255,255,255,0.55)" }}>
            <span style={{ fontSize:20, opacity:0.4 }}>🔒</span>
            <span style={{ fontFamily:"Georgia, serif", fontSize:9, color:"#6a9aaa", letterSpacing:1.5 }}>Coming Soon</span>
          </div>
        ))}
      </div>
      <p style={{ textAlign:"center", fontFamily:"Georgia, serif", fontSize:11,
        color:"rgba(44,74,82,0.5)", marginBottom:28, fontStyle:"italic" }}>
        find your still
      </p>
    </div>
  );
}

// ─── APP ROOT ─────────────────────────────────────────────────────────────────
export default function CalmCanvas() {
  const [screen, setScreen]     = useState("home");
  const [activeArt, setActiveArt] = useState("tiger");
  const [progress, setProgress] = useState({ tiger:0, satori:0 });
  const audio = useAmbientAudio();
  return (
    <div style={{ maxWidth:430, margin:"0 auto", position:"relative", minHeight:"100vh" }}>
      {screen==="home"
        ? <HomeScreen onSelectImage={(id)=>{ setActiveArt(id); setScreen("image"); }} progress={progress}/>
        : <ImageView artId={activeArt} onBack={() => setScreen("home")} audio={audio}
            onProgress={(pct)=>setProgress(p=>({...p,[activeArt]:pct}))}/>}
    </div>
  );
}
